import {
  createContext,
  useContext,
  useMemo,
  useReducer,
  type PropsWithChildren,
} from 'react';

import { UISegmentsDispatchContext } from './SegmentsUIDispatchContext.js';
import {
  segmentsUIReducer,
  type SegmentSelectorUIState,
} from './SegmentsUIReducer.js';
import type { UISegment } from './UISegments.types.js';
import type { OverlayTriggerState } from '../../../../overlays/hooks/useOverlay.js';
import { useSegments } from '../../hooks/useSegments.js';

/** @internal */
export const UISegmentsContext = createContext<SegmentSelectorUIState>({
  uiSegments: [],
  hasSelection: false,
  readOnly: false,
  isTouched: false,
});

/** @internal */
export const useSegmentsUIContext = () => {
  const { dispatch } = useContext(UISegmentsDispatchContext);

  function addUISegment(
    newSegment?: UISegment,
    isPlaceholder: boolean = false,
  ) {
    dispatch({
      type: 'add',
      payload: { segments: newSegment, isPlaceholder },
    });
  }

  function removeUISegment(id?: string | null) {
    if (id) {
      dispatch({ type: 'remove', payload: { id } });
    }
  }

  function removeAllUISegments() {
    dispatch({ type: 'removeAll' });
  }

  function updateUISegment(oldSegment: UISegment, newSegment: UISegment) {
    dispatch({ type: 'update', payload: { newSegment, oldSegment } });
  }

  function clearPlaceholder() {
    dispatch({ type: 'clearPlaceholder' });
  }

  function setUISegments(
    uiSegments: SegmentSelectorUIState['uiSegments'],
    hasSelection?: boolean,
  ) {
    dispatch({ type: 'setUISegments', payload: { uiSegments, hasSelection } });
  }

  function setArrayIdentifierError(hasError: boolean, id: string) {
    dispatch({ type: 'setArrayIdentifierError', payload: { hasError, id } });
  }

  return {
    removeAllUISegments,
    removeUISegment,
    addUISegment,
    updateUISegment,
    clearPlaceholder,
    setUISegments,
    setArrayIdentifierError,
  };
};

/**
 * Provider for the UISegments context that stores the selected segments in the proper order.
 * @param props - children only
 * @internal
 */
export const UISegmentsProvider = (
  props: PropsWithChildren<{
    readOnly?: boolean;
    overlayState: OverlayTriggerState;
  }>,
) => {
  const { children, readOnly, overlayState } = props;
  const { segments } = useSegments();

  const hasSelection = segments.length > 0;
  const id = segments[0]?.id ?? crypto.randomUUID();

  const [state, dispatch] = useReducer(segmentsUIReducer, {
    uiSegments: hasSelection ? segments : [{ id, isPlaceholder: true }],
    hasSelection,
    readOnly,
    focusedSegmentId: id,
    isTouched: false,
  });

  const dispatchContext = useMemo(
    () => ({ dispatch, overlayState }),
    [dispatch, overlayState],
  );

  return (
    <UISegmentsContext.Provider value={state}>
      <UISegmentsDispatchContext.Provider value={dispatchContext}>
        {children}
      </UISegmentsDispatchContext.Provider>
    </UISegmentsContext.Provider>
  );
};
